#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/mount.h>
#include <sys/stat.h>
#include <errno.h>
#include <mntent.h>
#include <limits.h>

/* 
 * File System Mount Operations in C
 * Demonstrates mount system calls and /etc/fstab parsing
 */

#define MAX_MOUNT_ENTRIES 64
#define MAX_PATH_LENGTH 256

/* Mount entry structure for our in-memory mount table */
typedef struct {
 char device[MAX_PATH_LENGTH]; /* Device path (e.g., /dev/sda1) */
 char mount_point[MAX_PATH_LENGTH]; /* Mount point (e.g., /home) */
 char fs_type[16]; /* File system type (e.g., ext4) */
 unsigned long options; /* Mount flags */
 int is_mounted; /* 1 if currently mounted */
} MountEntry;

/* Global mount table */
static MountEntry mount_table[MAX_MOUNT_ENTRIES];
static int mount_count = 0;

/* Mount option flags */
#define MS_RDONLY 1 /* Read-only */
#define MS_NOSUID 2 /* Ignore suid/sgid */
#define MS_NODEV 4 /* No device files */
#define MS_NOEXEC 8 /* No executable */
#define MS_SYNCHRONOUS 16 /* Synchronous writes */

/* Function to add entry to our mount table */
int add_mount_entry(const char *device, const char *mount_point, 
 const char *fs_type, unsigned long options) {
 if (mount_count >= MAX_MOUNT_ENTRIES) {
 fprintf(stderr, "Error: Mount table full\n");
 return -1;
 }

 MountEntry *entry = &mount_table[mount_count++];
 strncpy(entry->device, device, MAX_PATH_LENGTH - 1);
 strncpy(entry->mount_point, mount_point, MAX_PATH_LENGTH - 1);
 strncpy(entry->fs_type, fs_type, 15);
 entry->options = options;
 entry->is_mounted = 1;

 return 0;
}

/* Mount a file system using the mount() system call */
int mount_filesystem(const char *source, const char *target, 
 const char *fs_type, const char *options) {
 unsigned long mount_flags = 0;

 /* Parse mount options */
 if (options != NULL) {
 if (strstr(options, "ro") != NULL)
 mount_flags |= MS_RDONLY;
 if (strstr(options, "nosuid") != NULL)
 mount_flags |= MS_NOSUID;
 if (strstr(options, "nodev") != NULL)
 mount_flags |= MS_NODEV;
 if (strstr(options, "noexec") != NULL)
 mount_flags |= MS_NOEXEC;
 if (strstr(options, "sync") != NULL)
 mount_flags |= MS_SYNCHRONOUS;
 }

 /* Create mount point directory if it doesn't exist */
 struct stat st;
 if (stat(target, &st) != 0) {
 if (mkdir(target, 0755) != 0) {
 perror("mkdir");
 return -1;
 }
 }

 /* Perform the mount system call */
 if (mount(source, target, fs_type, mount_flags, NULL) != 0) {
 perror("mount");
 return -1;
 }

 /* Add to our mount table */
 add_mount_entry(source, target, fs_type, mount_flags);

 printf("Successfully mounted %s at %s (type: %s)\n", 
 source, target, fs_type);
 return 0;
}

/* Unmount a file system */
int unmount_filesystem(const char *mount_point) {
 /* Try to unmount */
 if (umount(mount_point) != 0) {
 perror("umount");
 return -1;
 }

 /* Remove from our mount table */
 for (int i = 0; i < mount_count; i++) {
 if (strcmp(mount_table[i].mount_point, mount_point) == 0) {
 mount_table[i].is_mounted = 0;
 break;
 }
 }

 printf("Successfully unmounted %s\n", mount_point);
 return 0;
}

/* Display current mount table using /proc/mounts */
void display_mounts(void) {
 FILE *mtab;
 struct mntent *mnt;

 printf("\n=== Current Mounts ===\n");
 printf("%-20s %-20s %-10s %s\n", 
 "Device", "Mount Point", "Type", "Options");
 printf("--------------------------------------------------------\n");

 mtab = setmntent("/proc/mounts", "r");
 if (mtab == NULL) {
 perror("setmntent");
 return;
 }

 while ((mnt = getmntent(mtab)) != NULL) {
 printf("%-20s %-20s %-10s %s\n",
 mnt->mnt_fsname,
 mnt->mnt_dir,
 mnt->mnt_type,
 mnt->mnt_opts);
 }

 endmntent(mtab);
 printf("\n");
}

/* Parse /etc/fstab and return mount entries */
void parse_fstab(void) {
 FILE *fstab;
 struct mntent *mnt;

 printf("\n=== Parsing /etc/fstab ===\n");

 fstab = setmntent("/etc/fstab", "r");
 if (fstab == NULL) {
 printf("Could not open /etc/fstab\n");
 return;
 }

 printf("%-20s %-20s %-10s %s\n", 
 "Device", "Mount Point", "Type", "Options");
 printf("--------------------------------------------------------\n");

 while ((mnt = getmntent(fstab)) != NULL) {
 /* Skip comments and swap entries */
 if (mnt->mnt_fsname[0] == '#' ||
 strcmp(mnt->mnt_type, "swap") == 0)
 continue;

 printf("%-20s %-20s %-10s %s\n",
 mnt->mnt_fsname,
 mnt->mnt_dir,
 mnt->mnt_type,
 mnt->mnt_opts);
 }

 endmntent(fstab);
 printf("\n");
}

/* Find mount point for a given path */
const char* find_mount_point(const char *path) {
 FILE *mtab;
 struct mntent *mnt;
 static char best_match[MAX_PATH_LENGTH] = "";
 int best_len = 0;

 mtab = setmntent("/proc/mounts", "r");
 if (mtab == NULL)
 return NULL;

 while ((mnt = getmntent(mtab)) != NULL) {
 /* Check if path starts with this mount point */
 if (strncmp(path, mnt->mnt_dir, strlen(mnt->mnt_dir)) == 0) {
 if (strlen(mnt->mnt_dir) > best_len) {
 best_len = strlen(mnt->mnt_dir);
 strncpy(best_match, mnt->mnt_dir, MAX_PATH_LENGTH - 1);
 }
 }
 }

 endmntent(mtab);

 return best_len > 0 ? best_match : NULL;
}

/* Main demonstration */
int main(void) {
 printf("=== File System Mount Operations in C ===\n");

 /* Display current mounts from /proc/mounts */
 display_mounts();

 /* Parse /etc/fstab */
 parse_fstab();

 /* Demonstrate path resolution */
 printf("=== Path Resolution Demo ===\n");
 const char *test_paths[] = {"/home/user/file.txt", 
 "/var/log/syslog",
 "/mnt/usb/data.pdf"};

 for (int i = 0; i < 3; i++) {
 const char *mount_pt = find_mount_point(test_paths[i]);
 if (mount_pt) {
 printf("Path: %s\n", test_paths[i]);
 printf(" -> Mount point: %s\n", mount_pt);
 printf(" -> Relative path: %s\n\n", 
 test_paths[i] + strlen(mount_pt));
 }
 }

 /* Note: Actual mount/unmount requires root privileges */
 printf("Note: mount/umount system calls require root privileges.\n");
 printf("This program demonstrates reading mount information.\n");

 return 0;
}
